const fs = require('fs');
const path = require('path');
const yaml = require('js-yaml');

const dataFolder = './data_folder';
const secretsFile = path.join(dataFolder, 'secrets.yaml');
const configFile = path.join(dataFolder, 'work_preferences.yaml');
const resumeFile = path.join(dataFolder, 'plain_text_resume.yaml');

if (!fs.existsSync(dataFolder)) {
  throw new Error(`Data folder not found: ${dataFolder}`);
}

if (!fs.existsSync(secretsFile)) {
  throw new Error(`Secrets file not found: ${secretsFile}`);
}

if (!fs.existsSync(configFile)) {
  throw new Error(`Config file not found: ${configFile}`);
}

if (!fs.existsSync(resumeFile)) {
  throw new Error(`Resume file not found: ${resumeFile}`);
}

const secrets = yaml.load(fs.readFileSync(secretsFile, 'utf8'));
const config = yaml.load(fs.readFileSync(configFile, 'utf8'));
const resume = yaml.load(fs.readFileSync(resumeFile, 'utf8'));

if (!secrets.llm_api_key) {
  throw new Error('LLM API key not found in secrets.yaml');
}

return {
  llm_api_key: secrets.llm_api_key,
  config: config,
  resume: resume,
  dataFolder: dataFolder,
  outputFolder: path.join(dataFolder, 'output')
};

const fs = require('fs');
const path = require('path');

const outputFolder = $input.all()[0].json.outputFolder;

if (!fs.existsSync(outputFolder)) {
  fs.mkdirSync(outputFolder, { recursive: true });
}

return {
  outputFolder: outputFolder,
  timestamp: new Date().toISOString()
};

const action = $input.all()[0].json.action || '';

return {
  action: action.toString().toLowerCase(),
  isGenerateResume: action === 'Generate Resume',
  isGenerateResumeTailored: action === 'Generate Resume Tailored for Job Description',
  isGenerateCoverLetter: action === 'Generate Tailored Cover Letter for Job Description'
};

const fs = require('fs');
const path = require('path');

const allData = $input.all();
const configData = allData.find(item => item.json.config);
const outputFolder = allData.find(item => item.json.outputFolder)?.json.outputFolder;

const plainTextResume = configData.json.resume.personal_information.name || '';

return {
  status: 'resume_generated',
  name: plainTextResume,
  timestamp: new Date().toISOString(),
  outputPath: path.join(outputFolder || './data_folder/output', 'resume_base.pdf'),
  message: 'Resume PDF generated successfully'
};

const fs = require('fs');
const path = require('path');

const allData = $input.all();
const configData = allData.find(item => item.json.config);
const outputFolder = allData.find(item => item.json.outputFolder)?.json.outputFolder;
const jobUrl = $input.all()[0].json.jobUrl || '';

const plainTextResume = configData.json.resume.personal_information.name || '';
const jobTitle = jobUrl.split('/').pop().replace(/-/g, ' ') || 'tailored';

return {
  status: 'resume_tailored_generated',
  jobUrl: jobUrl,
  jobTitle: jobTitle,
  candidateName: plainTextResume,
  timestamp: new Date().toISOString(),
  outputPath: path.join(outputFolder || './data_folder/output', jobTitle, 'resume_tailored.pdf'),
  message: 'Tailored resume PDF generated successfully'
};

const fs = require('fs');
const path = require('path');

const allData = $input.all();
const configData = allData.find(item => item.json.config);
const outputFolder = allData.find(item => item.json.outputFolder)?.json.outputFolder;
const jobUrl = $input.all()[0].json.jobUrl || '';

const plainTextResume = configData.json.resume.personal_information.name || '';
const jobTitle = jobUrl.split('/').pop().replace(/-/g, ' ') || 'cover_letter';

return {
  status: 'cover_letter_generated',
  jobUrl: jobUrl,
  jobTitle: jobTitle,
  candidateName: plainTextResume,
  timestamp: new Date().toISOString(),
  outputPath: path.join(outputFolder || './data_folder/output', jobTitle, 'cover_letter_tailored.pdf'),
  message: 'Tailored cover letter PDF generated successfully'
};

const results = $input.all();
const successResults = results.filter(r => r.json.status);

return {
  totalProcessed: successResults.length,
  results: successResults.map(r => ({
    status: r.json.status,
    timestamp: r.json.timestamp,
    message: r.json.message,
    outputPath: r.json.outputPath
  })),
  completedAt: new Date().toISOString()
};
